INSERT INTO "public"."iam_roles" ("id", "academy_id", "code", "name", "description", "is_system", "is_active", "priority", "created_at", "updated_at", "deleted_at", "deleted_by", "created_by", "updated_by") VALUES
('83cd348c-3ed1-4f24-9c91-50b26c0927c4', NULL, 'super_admin', 'Super Admin', 'Platform-level administrator. Has every permission across every academy.', TRUE, TRUE, 10, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('1851199c-1d8f-44d2-bed0-1e0f6de6bb8a', NULL, 'academy_owner', 'Academy Owner', 'Full control over a single academy. Holds every academy-level capability including role management, settings, and refunds.', TRUE, TRUE, 20, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('e5a298be-d084-49e3-beca-f36b98e325e5', NULL, 'academy_admin', 'Academy Admin', 'Day-to-day administrator. Same as owner minus: admin.role.manage, admin.settings.update, admin.user.delete, admin.session.revoke, admin.audit.export, payment.refund, evaluation.delete.', TRUE, TRUE, 30, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('689a8873-dc82-42f5-8a92-654418be9855', NULL, 'branch_manager', 'Branch Manager', 'Manages players, coaches, and operations within a single branch. Cannot export academy-wide data (export perms are academy-scoped and intentionally withheld).', TRUE, TRUE, 40, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('504ea25b-3d03-4959-b6c0-3f1151d15e23', NULL, 'head_coach', 'Head Coach', 'Lead coach of one or more groups. Marks attendance, evaluates players.', TRUE, TRUE, 50, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('46f9084f-65df-41c9-8fec-fb6705346233', NULL, 'assistant_coach', 'Assistant Coach', 'Supports the head coach. Can mark attendance and view evaluations.', TRUE, TRUE, 60, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('ecb5f4de-88ae-4b8c-b87c-5c02b873e3e3', NULL, 'player', 'Player', 'Athlete account. Read-only access to own data.', TRUE, TRUE, 90, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL),
('b5ef2068-570c-47ba-8649-2e8667ba11fc', NULL, 'parent', 'Parent / Guardian', 'Guardian account. Read-only access to linked children + payments. NOTE: middleware must interpret ''*.read.self'' permissions as ''own profile OR linked children via guardian_player_links''.', TRUE, TRUE, 95, '2026-05-15T15:50:43.177Z', '2026-05-16T22:11:41.536Z', NULL, NULL, NULL, NULL);
